mapper.select:
SELECT c.id, c.article_id, c.parent_id, c.content, c.commentator_id, c.commentator_name, u.avatar as user_avatar, c.reply_to_id, c.reply_to_name, c.like_count, c.status, c.del_flag, c.create_by, c.create_time, c.update_by, c.update_time FROM psi_blog_comment c LEFT JOIN sys_blog_user u ON c.commentator_id = u.id WHERE c.del_flag = '0' AND c.status = '1' AND c.parent_id IN
#{parentId}
ORDER BY c.create_time ASC

mapper.delete:
UPDATE psi_blog_comment
SET del_flag = '1'
WHERE article_id = #{articleId}
